def count_subarrays(nums):
    n = len(nums)
    count = 0
    stack = []

    for i in range(n):
        while stack and nums[stack[-1]] < nums[i]:
            stack.pop()
        if stack and nums[stack[-1]] == nums[i]:
            count += (i - stack[-1])
        else:
            count += 1
        stack.append(i)

    return count
